unitsize(1.5 cm);

pair A,B,C,M;
A=(0,0);
C=(4,0);
B=(1.5,1.5);
M=(2.75,0.75);
draw(A--B--C--cycle,linewidth(0.7));
draw(A--M,linewidth(0.7));
label("$a$",(2.13,1.04),NE);
label("$a$",(3.3,0.38),NE);
label("$2a$",(1.4,0.38),N);
label("2",(2,0),S);
label("1",(A + B)/2,NW);
label("$A$",A,SW);
label("$C$",C,SE);
label("$B$",B,N);
label("$M$",(B+ C)/2,NE);
[/asy]

